from google.cloud import storage, firestore, pubsub_v1
import base64
import json
import os
from datetime import datetime, timezone

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

OUTPUT_COLLECTION = os.getenv("OUTPUT_COLLECTION", "processed_files")
PUBSUB_TOPIC = os.getenv("PUBSUB_TOPIC", "")
PROJECT_ID = os.getenv("GCP_PROJECT") or os.getenv("GOOGLE_CLOUD_PROJECT")

def process_gcs_file(event, context):
    bucket_name = event["bucket"]
    file_name = event["name"]

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    content = blob.download_as_bytes()

    doc = {
        "bucket": bucket_name,
        "name": file_name,
        "size": event.get("size"),
        "content_type": event.get("contentType"),
        "time_created": event.get("timeCreated"),
        "updated": event.get("updated"),
        "processed_at": datetime.now(timezone.utc).isoformat(),
        "content_b64": base64.b64encode(content).decode("utf-8"),
    }

    firestore_client.collection(OUTPUT_COLLECTION).document(file_name.replace("/", "_")).set(doc)

    if PUBSUB_TOPIC:
        topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
        message = {
            "bucket": bucket_name,
            "name": file_name,
            "processed_at": doc["processed_at"],
        }
        publisher.publish(topic_path, json.dumps(message).encode("utf-8")).result()

    return "OK"

